<?php
namespace Tests\Feature;
use App\Domain\GameHome\GameHomeCardDestinationType;use App\Domain\Shops\ShopLocationType;use App\Models\Character;use App\Models\GameHomeCard;use App\Models\Shop;use App\Models\ShopLocation;use App\Models\User;use App\Models\Zone;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
final class GameHomeShopIntegrationTest extends TestCase{use RefreshDatabase;
 private function data($shop,$code='global-shop-card'){return['name'=>'Mercado','code'=>$code,'destination_type'=>GameHomeCardDestinationType::SHOP,'destination_value'=>(string)$shop->id,'sort_order'=>1,'is_active'=>1,'opens_new_tab'=>0];}
 public function test_admin_selects_global_shop_and_home_resolves_active_character_url(){config(['game_admin.emails'=>['admin@example.test']]);$admin=User::factory()->create(['email'=>'admin@example.test']);$shop=Shop::factory()->create(['name'=>'Mercado global']);$this->actingAs($admin)->post(route('admin.content.game-home-cards.store'),$this->data($shop))->assertRedirect();$card=GameHomeCard::where('code','global-shop-card')->firstOrFail();$this->assertSame((string)$shop->id,$card->destination_value);$character=Character::factory()->selectedFor($player=User::factory()->create())->create();$this->actingAs($player)->get(route('dashboard'))->assertOk()->assertSee(route('characters.shops.show',[$character,$shop]),false);}
 public function test_localized_or_inactive_shop_cannot_be_configured_as_global(){config(['game_admin.emails'=>['admin@example.test']]);$admin=User::factory()->create(['email'=>'admin@example.test']);$this->seed(WorldCatalogSeeder::class);$zone=Zone::where('code','grey_oak_forest')->firstOrFail();$localized=Shop::factory()->create();ShopLocation::create(['shop_id'=>$localized->id,'locatable_type'=>ShopLocationType::ZONE,'locatable_id'=>$zone->id,'status'=>'active','sort_order'=>0]);$this->actingAs($admin)->post(route('admin.content.game-home-cards.store'),$this->data($localized))->assertSessionHasErrors('destination_value');$inactive=Shop::factory()->create(['status'=>'inactive']);$this->post(route('admin.content.game-home-cards.store'),$this->data($inactive,'inactive-shop-card'))->assertSessionHasErrors('destination_value');}
}
